/**
 * ─────────────────────────────────────────────────────────
 *  NUNTIO — "tempus fugit"
 *  Compact popup · Timer · Tasks · Notes
 *  Logo: galaxy spiral (fixed, static)
 * ─────────────────────────────────────────────────────────
 */

import { useState, useEffect, useRef, useCallback } from "react";

// ── Constants ─────────────────────────────────────────────
const FOCUS_DURATION = 25 * 60;
const BREAK_DURATION = 5 * 60;
const STICKY_ROTATIONS = [-2.5, 1.8, -1.2, 2.1, -0.8, 1.5, -2.0];
let stickyIdCounter = 1;

// ── Sticky color palettes ─────────────────────────────────
const STICKY_COLORS = [
  { bg: "#FFF8DC", border: "#E8D97A", label: "Maize" },
  { bg: "#FCE4EC", border: "#E8A0B0", label: "Blush" },
  { bg: "#E8F5E9", border: "#9AC89D", label: "Sage" },
  { bg: "#E3F2FD", border: "#90BAD8", label: "Sky" },
  { bg: "#F3E5F5", border: "#C8A0D0", label: "Lilac" },
];

// ── Galaxy logo (base64, embedded) ────────────────────────
const LOGO_SRC = "data:image/jpeg;base64,";

// ── Global CSS ────────────────────────────────────────────
const GLOBAL_CSS = `
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;1,400&family=DM+Mono:wght@300;400&family=Caveat:wght@400;500&display=swap');

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html, body { height: 100%; background: #D8D4CC; }

:root {
  --cream:      #F5F2EC;
  --ink:        #1A1714;
  --ink-hover:  #2e2b27;
  --warm-gray:  #8C8680;
  --accent:     #C9A96E;
  --panel-bg:   #EDEAE3;
  --light-rule: rgba(26,23,20,0.10);
}

@keyframes fadeUp  { from { opacity:0; transform:translateY(8px);  } to { opacity:1; transform:translateY(0);   } }
@keyframes tabIn   { from { opacity:0; transform:translateX(5px);  } to { opacity:1; transform:translateX(0);   } }
@keyframes drawLine{ from { transform:scaleX(0); } to { transform:scaleX(1); } }
@keyframes pulse   { 0%,100%{opacity:1;} 50%{opacity:.5;} }
@keyframes spin    { from{transform:rotate(0deg);} to{transform:rotate(360deg);} }
@keyframes checkIn { from{transform:scale(.4);opacity:0;} to{transform:scale(1);opacity:1;} }
@keyframes stickyIn{ from{opacity:0;transform:scale(.88) rotate(var(--rot));} to{opacity:1;transform:scale(1) rotate(var(--rot));} }

/* ── Shell ── */
.shell {
  min-height:100vh; display:flex;
  align-items:center; justify-content:center; padding:24px;
}
/* drag region */
.drag-handle {
  -webkit-app-region: drag;
  cursor: move;
}
.drag-handle button,
.drag-handle input,
.drag-handle textarea {
  -webkit-app-region: no-drag;
}

.popup {
  width:320px; background:var(--cream); border-radius:3px; overflow:hidden;
  box-shadow:0 4px 24px rgba(0,0,0,.14),0 1px 4px rgba(0,0,0,.08);
  animation:fadeUp .5s ease both;
  font-family:'DM Mono',monospace; color:var(--ink);
}

/* ── Header ── */
.popup-header { padding:16px 20px 0; }
.top-rule {
  height:2px; background:var(--ink); margin-bottom:12px;
  transform-origin:left; animation:drawLine .4s cubic-bezier(.76,0,.24,1) .1s both;
}
.brand-row { display:flex; align-items:center; gap:10px; margin-bottom:14px; }

/* Galaxy logo — fixed size, slow spin only on hover */
.logo-img {
  width:32px; height:32px; object-fit:cover; border-radius:50%;
  flex-shrink:0;
  filter: invert(1);           /* white galaxy on dark → dark on cream */
  mix-blend-mode: multiply;
  transition: filter .3s;
}
.logo-img:hover { animation: spin 8s linear infinite; }

.brand-text { display:flex; flex-direction:column; }
.brand-name {
  font-family:'Playfair Display',serif; font-style:italic;
  font-size:18px; font-weight:400; line-height:1;
}
.brand-tagline {
  font-size:7px; font-weight:300; letter-spacing:.16em;
  text-transform:uppercase; color:var(--warm-gray); margin-top:2px;
}

/* ── Tab nav ── */
.tab-nav { display:flex; border-bottom:1px solid var(--light-rule); }
.tab-btn {
  flex:1; font-family:'DM Mono',monospace; font-size:8px; font-weight:300;
  letter-spacing:.18em; text-transform:uppercase; color:var(--warm-gray);
  background:none; border:none; border-bottom:2px solid transparent;
  padding:8px 0 9px; margin-bottom:-1px; cursor:pointer;
  transition:color .2s,border-color .2s;
}
.tab-btn.active { color:var(--ink); border-bottom-color:var(--ink); }

/* ── Tab content ── */
.tab-content { padding:18px 20px 20px; animation:tabIn .22s ease both; }

/* ═══ TIMER ═══ */
.mode-row {
  display:flex; border-bottom:1px solid var(--light-rule); margin-bottom:14px;
}
.mode-btn {
  font-family:'DM Mono',monospace; font-size:8px; font-weight:300;
  letter-spacing:.15em; text-transform:uppercase; color:var(--warm-gray);
  background:none; border:none; border-bottom:2px solid transparent;
  padding:0 0 8px; margin-bottom:-1px; margin-right:16px; cursor:pointer;
  transition:color .2s,border-color .2s;
}
.mode-btn.active { color:var(--ink); border-bottom-color:var(--ink); }

.time-display {
  font-family:'Playfair Display',serif; font-size:64px; font-weight:400;
  letter-spacing:-.04em; line-height:1; text-align:center; margin-bottom:10px;
}
.time-display.running { animation:pulse 2s ease-in-out infinite; }

.progress-track { height:1px; background:var(--light-rule); position:relative; margin-bottom:5px; }
.progress-fill  { position:absolute; inset:0; background:var(--ink); transition:width .9s linear; }
.progress-label {
  font-size:8px; font-weight:300; letter-spacing:.14em;
  text-transform:uppercase; color:var(--warm-gray);
  text-align:center; margin-bottom:18px;
}

.controls { display:flex; gap:8px; justify-content:center; margin-bottom:6px; }
.btn-main {
  font-family:'DM Mono',monospace; font-size:9px; font-weight:400;
  letter-spacing:.18em; text-transform:uppercase;
  background:var(--ink); color:var(--cream); border:none;
  padding:10px 24px; cursor:pointer; border-radius:1px;
  transition:background .2s,transform .1s;
}
.btn-main:hover  { background:var(--ink-hover); }
.btn-main:active { transform:scale(.97); }
.btn-ghost {
  font-family:'DM Mono',monospace; font-size:9px; font-weight:300;
  letter-spacing:.12em; text-transform:uppercase;
  background:none; color:var(--warm-gray);
  border:1px solid var(--light-rule); padding:9px 14px;
  cursor:pointer; border-radius:1px; transition:color .2s,border-color .2s;
}
.btn-ghost:hover { color:var(--ink); border-color:rgba(26,23,20,.3); }
.sessions-count {
  font-size:8px; letter-spacing:.12em; color:var(--warm-gray);
  text-align:center; margin-top:8px;
}

/* ═══ TASKS ═══ */
.task-list { margin-bottom:14px; }
.task-item {
  display:flex; align-items:center; gap:10px;
  padding:11px 0; border-bottom:1px solid var(--light-rule);
}
.task-item:first-child { border-top:1px solid var(--light-rule); }
.task-check {
  width:14px; height:14px; flex-shrink:0;
  border:1px solid rgba(26,23,20,.25);
  display:flex; align-items:center; justify-content:center;
  cursor:pointer; transition:background .2s,border-color .2s;
}
.task-check.done { background:var(--ink); border-color:var(--ink); }
.check-mark { animation:checkIn .2s ease; }
.task-input {
  flex:1; font-family:'DM Mono',monospace; font-size:10px; font-weight:300;
  letter-spacing:.04em; color:var(--ink); background:none;
  border:none; outline:none; transition:opacity .2s;
}
.task-input::placeholder { color:rgba(140,134,128,.4); }
.task-input.done { opacity:.3; text-decoration:line-through; text-decoration-color:rgba(26,23,20,.3); }
.task-num {
  font-family:'Playfair Display',serif; font-style:italic;
  font-size:10px; color:rgba(140,134,128,.35);
}
.tasks-footer {
  display:flex; justify-content:space-between; align-items:center;
  padding-top:14px; border-top:1px solid var(--light-rule);
}
.footer-stat { font-size:8px; font-weight:300; letter-spacing:.12em; text-transform:uppercase; color:var(--warm-gray); }
.footer-stat span { font-family:'Playfair Display',serif; font-style:italic; font-size:12px; color:var(--ink); margin-left:4px; }
.dot-row { display:flex; gap:4px; }
.dot {
  width:5px; height:5px; border-radius:50%;
  background:transparent; border:1px solid rgba(26,23,20,.2);
  transition:background .3s,border-color .3s;
}
.dot.filled { background:var(--accent); border-color:var(--accent); }

/* ═══ NOTES ═══ */
.tab-content.notes-tab { background:var(--panel-bg); padding:14px 16px 18px; }
.notes-header { display:flex; align-items:center; justify-content:space-between; margin-bottom:10px; }
.notes-title { font-size:8px; font-weight:300; letter-spacing:.2em; text-transform:uppercase; color:var(--warm-gray); }
.add-note-btn {
  font-family:'DM Mono',monospace; font-size:8px; font-weight:400;
  letter-spacing:.16em; text-transform:uppercase;
  background:var(--ink); color:var(--cream); border:none;
  padding:7px 12px; cursor:pointer; border-radius:1px; transition:background .2s;
}
.add-note-btn:hover { background:var(--ink-hover); }
.color-picker { display:flex; gap:6px; margin-bottom:12px; }
.color-swatch {
  width:14px; height:14px; border-radius:50%;
  cursor:pointer; transition:transform .15s; border:2px solid transparent;
}
.color-swatch:hover  { transform:scale(1.2); }
.color-swatch.active { transform:scale(1.2); border-color:var(--ink) !important; }
.stickies-canvas { position:relative; height:270px; overflow:hidden; }
.sticky {
  position:absolute; width:130px; min-height:110px;
  padding:14px 12px 10px; border-radius:2px;
  display:flex; flex-direction:column;
  box-shadow:2px 3px 10px rgba(0,0,0,.10),0 1px 3px rgba(0,0,0,.06);
  cursor:grab; user-select:none;
  animation:stickyIn .25s ease both; transition:box-shadow .2s;
}
.sticky:active   { cursor:grabbing; }
.sticky.dragging { box-shadow:6px 8px 22px rgba(0,0,0,.18),0 2px 5px rgba(0,0,0,.10); z-index:100; }
.sticky-tape {
  position:absolute; top:-8px; left:50%; transform:translateX(-50%);
  width:34px; height:16px; background:rgba(255,255,255,.55);
  border-radius:1px; box-shadow:0 1px 3px rgba(0,0,0,.08);
}
.sticky-header {
  display:flex; align-items:center; justify-content:space-between;
  margin-bottom:7px; padding-bottom:6px; border-bottom:1px solid rgba(0,0,0,.07);
}
.sticky-date { font-size:7px; font-weight:300; letter-spacing:.1em; text-transform:uppercase; color:rgba(26,23,20,.4); }
.sticky-delete {
  background:none; border:none; font-size:12px; line-height:1;
  color:rgba(26,23,20,.25); cursor:pointer; padding:0; transition:color .15s;
}
.sticky-delete:hover { color:rgba(26,23,20,.65); }
.sticky-textarea {
  flex:1; font-family:'Caveat',cursive; font-size:14px;
  font-weight:400; line-height:1.5; color:rgba(26,23,20,.85);
  background:none; border:none; outline:none; resize:none; width:100%; min-height:55px;
}
.sticky-textarea::placeholder { color:rgba(26,23,20,.25); }
.empty-state {
  position:absolute; top:50%; left:50%;
  transform:translate(-50%,-50%); text-align:center; pointer-events:none;
}
.empty-icon  { font-family:'Playfair Display',serif; font-style:italic; font-size:30px; color:rgba(26,23,20,.08); margin-bottom:6px; }
.empty-text  { font-size:8px; letter-spacing:.18em; text-transform:uppercase; color:rgba(26,23,20,.20); }
`;

// ── Helpers ───────────────────────────────────────────────
const formatTime = (s) => `${Math.floor(s / 60).toString().padStart(2, "0")}:${(s % 60).toString().padStart(2, "0")}`;
const shortDate = () => new Date().toLocaleDateString("en-US", { month: "short", day: "numeric" });
const todayLabel = () => new Date().toLocaleDateString("en-US", { weekday: "long" });

// ── Sub-components ────────────────────────────────────────
function CheckIcon() {
  return (
    <svg className="check-mark" width="8" height="6" viewBox="0 0 8 6" fill="none">
      <path d="M1 3L3 5L7 1" stroke="#F5F2EC" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function TaskItem({ task, index, onToggle, onChange }) {
  return (
    <div className="task-item">
      <div className={`task-check ${task.done ? "done" : ""}`} onClick={onToggle} role="checkbox" aria-checked={task.done}>
        {task.done && <CheckIcon />}
      </div>
      <input
        className={`task-input ${task.done ? "done" : ""}`}
        placeholder="Add a task…" value={task.text}
        onChange={(e) => onChange(e.target.value)}
        readOnly={task.done} maxLength={40}
      />
      <span className="task-num">{(index + 1).toString().padStart(2, "0")}</span>
    </div>
  );
}

function StickyNote({ note, isDragging, onMouseDown, onDelete, onChange }) {
  const p = STICKY_COLORS[note.color];
  return (
    <div
      className={`sticky ${isDragging ? "dragging" : ""}`}
      style={{
        left: note.x, top: note.y, background: p.bg, borderTop: `3px solid ${p.border}`,
        "--rot": `${note.rotation}deg`, transform: `rotate(${note.rotation}deg)`
      }}
      onMouseDown={onMouseDown}
    >
      <div className="sticky-tape" aria-hidden="true" />
      <div className="sticky-header">
        <span className="sticky-date">{note.date}</span>
        <button className="sticky-delete" onClick={onDelete}>×</button>
      </div>
      <textarea
        className="sticky-textarea" placeholder="Write…"
        value={note.text} onChange={(e) => onChange(e.target.value)} rows={4}
      />
    </div>
  );
}

// ── Main Component ────────────────────────────────────────
export default function Nuntio() {
  const [tab, setTab] = useState("timer");
  const [mode, setMode] = useState("focus");
  const [timeLeft, setTimeLeft] = useState(FOCUS_DURATION);
  const [running, setRunning] = useState(false);
  const [sessions, setSessions] = useState(0);
  const intervalRef = useRef(null);

  const [tasks, setTasks] = useState([
    { id: 1, text: "", done: false },
    { id: 2, text: "", done: false },
    { id: 3, text: "", done: false },
  ]);

  const [stickies, setStickies] = useState([]);
  const [selectedColor, setSelectedColor] = useState(0);
  const [draggingId, setDraggingId] = useState(null);
  const dragOffset = useRef({ x: 0, y: 0 });
  const canvasRef = useRef(null);

  const duration = mode === "focus" ? FOCUS_DURATION : BREAK_DURATION;
  const progressPct = ((duration - timeLeft) / duration) * 100;
  const doneCount = tasks.filter(t => t.done).length;

  // Timer
  const tick = useCallback(() => {
    setTimeLeft(prev => {
      if (prev <= 1) { setRunning(false); if (mode === "focus") setSessions(s => s + 1); return 0; }
      return prev - 1;
    });
  }, [mode]);

  useEffect(() => {
    if (running) intervalRef.current = setInterval(tick, 1000);
    else clearInterval(intervalRef.current);
    return () => clearInterval(intervalRef.current);
  }, [running, tick]);

  const switchMode = (m) => { setMode(m); setRunning(false); setTimeLeft(m === "focus" ? FOCUS_DURATION : BREAK_DURATION); };
  const resetTimer = () => { setRunning(false); setTimeLeft(duration); };

  // Tasks
  const toggleTask = (id) => setTasks(ts => ts.map(t => t.id === id ? { ...t, done: !t.done } : t));
  const updateTask = (id, text) => setTasks(ts => ts.map(t => t.id === id ? { ...t, text } : t));

  // Notes
  const addSticky = () => {
    const cv = canvasRef.current; const cw = cv ? cv.offsetWidth : 280; const ch = cv ? cv.offsetHeight : 270;
    const x = 10 + Math.random() * Math.max(0, cw - 150);
    const y = 10 + Math.random() * Math.max(0, ch - 130);
    const rot = STICKY_ROTATIONS[stickyIdCounter % STICKY_ROTATIONS.length];
    setStickies(p => [...p, { id: stickyIdCounter++, text: "", color: selectedColor, x, y, rotation: rot, date: shortDate() }]);
  };
  const deleteSticky = (id) => setStickies(s => s.filter(n => n.id !== id));
  const updateSticky = (id, text) => setStickies(s => s.map(n => n.id === id ? { ...n, text } : n));

  // Drag
  const handleMouseDown = (e, id) => {
    if (e.target.tagName === "TEXTAREA" || e.target.tagName === "BUTTON") return;
    e.preventDefault();
    const note = stickies.find(s => s.id === id);
    dragOffset.current = { x: e.clientX - note.x, y: e.clientY - note.y };
    setDraggingId(id);
    setStickies(prev => { const item = prev.find(n => n.id === id); return [...prev.filter(n => n.id !== id), item]; });
  };
  useEffect(() => {
    const onMove = (e) => { if (!draggingId) return; setStickies(prev => prev.map(n => n.id === draggingId ? { ...n, x: e.clientX - dragOffset.current.x, y: e.clientY - dragOffset.current.y } : n)); };
    const onUp = () => setDraggingId(null);
    window.addEventListener("mousemove", onMove); window.addEventListener("mouseup", onUp);
    return () => { window.removeEventListener("mousemove", onMove); window.removeEventListener("mouseup", onUp); };
  }, [draggingId]);

  return (
    <>
      <style>{GLOBAL_CSS}</style>
      <div className="shell">
        <div className="popup">

          {/* Header */}
          <div className="popup-header drag-handle">
            <div className="top-rule" />
            <div className="brand-row">
              <img src={LOGO_SRC} className="logo-img" alt="Nuntio logo" />
              <div className="brand-text">
                <span className="brand-name">Nuntio</span>
                <span className="brand-tagline">tempus fugit · {todayLabel()}</span>
              </div>
            </div>
            <div className="tab-nav" role="tablist">
              {[{ key: "timer", label: "Timer" }, { key: "tasks", label: "Tasks" }, { key: "notes", label: "Notes" }].map(({ key, label }) => (
                <button key={key} className={`tab-btn ${tab === key ? "active" : ""}`}
                  onClick={() => setTab(key)} role="tab" aria-selected={tab === key}>{label}</button>
              ))}
            </div>
          </div>

          {/* ── Timer ── */}
          {tab === "timer" && (
            <div className="tab-content" role="tabpanel">
              <div className="mode-row">
                <button className={`mode-btn ${mode === "focus" ? "active" : ""}`} onClick={() => switchMode("focus")}>Focus</button>
                <button className={`mode-btn ${mode === "break" ? "active" : ""}`} onClick={() => switchMode("break")}>Break</button>
              </div>
              <div className={`time-display ${running ? "running" : ""}`} aria-live="polite">{formatTime(timeLeft)}</div>
              <div className="progress-track"><div className="progress-fill" style={{ width: `${progressPct}%` }} /></div>
              <div className="progress-label">{mode === "focus" ? "Focus session" : "Short break"}</div>
              <div className="controls">
                <button className="btn-main" onClick={() => setRunning(r => !r)}>
                  {running ? "Pause" : timeLeft === 0 ? "Done" : "Start"}
                </button>
                <button className="btn-ghost" onClick={resetTimer}>Reset</button>
              </div>
              <div className="sessions-count">{sessions} session{sessions !== 1 ? "s" : ""} completed</div>
            </div>
          )}

          {/* ── Tasks ── */}
          {tab === "tasks" && (
            <div className="tab-content" role="tabpanel">
              <div className="task-list">
                {tasks.map((task, i) => (
                  <TaskItem key={task.id} task={task} index={i}
                    onToggle={() => toggleTask(task.id)} onChange={(text) => updateTask(task.id, text)} />
                ))}
              </div>
              <div className="tasks-footer">
                <div className="footer-stat">Done <span>{doneCount} / 3</span></div>
                <div className="dot-row">{tasks.map(t => <div key={t.id} className={`dot ${t.done ? "filled" : ""}`} />)}</div>
              </div>
            </div>
          )}

          {/* ── Notes ── */}
          {tab === "notes" && (
            <div className="tab-content notes-tab" role="tabpanel">
              <div className="notes-header">
                <span className="notes-title">Today's notes</span>
                <button className="add-note-btn" onClick={addSticky}>+ New</button>
              </div>
              <div className="color-picker">
                {STICKY_COLORS.map((c, i) => (
                  <div key={i} className={`color-swatch ${selectedColor === i ? "active" : ""}`}
                    style={{ background: c.bg, border: `2px solid ${selectedColor === i ? "var(--ink)" : c.border}` }}
                    onClick={() => setSelectedColor(i)} title={c.label} />
                ))}
              </div>
              <div className="stickies-canvas" ref={canvasRef}>
                {stickies.length === 0 && (
                  <div className="empty-state">
                    <div className="empty-icon">✦</div>
                    <div className="empty-text">Add your first note</div>
                  </div>
                )}
                {stickies.map(note => (
                  <StickyNote key={note.id} note={note} isDragging={draggingId === note.id}
                    onMouseDown={(e) => handleMouseDown(e, note.id)}
                    onDelete={() => deleteSticky(note.id)} onChange={(text) => updateSticky(note.id, text)} />
                ))}
              </div>
            </div>
          )}

        </div>
      </div>
    </>
  );
}
